INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", "カオリ（サマー）", 0.0, 4, 110501, 0.0, 1, "2019/07/31 12:00:00", 0.0, 4, 24015, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", "カオリ（サマー）", 4.0, 4, 110501, 0.0, 2, "2019/07/31 12:00:00", 0.0, 1, 24016, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "マジムンだらけで目が回るさ～！\nふらふらさ～！", "カオリ（サマー）", 0.0, 4, 110501, 0.0, 3, "2019/07/31 12:00:00", 0.0, 4, 24017, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", "カオリ（サマー）", 5.2, 1, 110501, 0.0, 4, "2019/07/31 12:00:00", 0.0, 2, 24018, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", "カオリ（サマー）", 4.2, 5, 110501, 0.0, 5, "2019/07/31 12:00:00", 0.0, 6, 24019, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", "カオリ（サマー）", 0.0, 2, 110501, 0.0, 6, "2019/07/31 12:00:00", 0.0, 2, 24020, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", "カオリ（サマー）", 6.4, 1, 110501, 0.0, 7, "2019/07/31 12:00:00", 0.0, 6, 24021, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", "カオリ（サマー）", 0.0, 2, 110501, 0.0, 8, "2019/07/31 12:00:00", 0.0, 2, 24022, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", "カオリ（サマー）", 10.08, 6, 110501, 0.0, 9, "2019/07/31 12:00:00", 0.0, 3, 24023, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", "カオリ（サマー）", 5.0, 1, 110501, 0.0, 10, "2019/07/31 12:00:00", 0.0, 2, 24024, "2030/12/17 14:59:59");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (10021, 24, "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", "カオリ（サマー）", 0.0, 2, 110501, 0.0, 11, "2019/07/31 12:00:00", 0.0, 2, 24025, "2030/12/17 14:59:59");
